import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a binary number?", a: "A binary number is a base-2 number that uses only 0 and 1. Each digit represents a power of 2. For example, binary 1011 equals 8 + 0 + 2 + 1 = 11 in decimal." },
  { q: "How do you add binary numbers?", a: "Binary addition works like decimal addition, but carries happen at 2 instead of 10. The basic rules are 0+0=0, 0+1=1, 1+0=1, and 1+1=10, meaning write 0 and carry 1." },
  { q: "How do you convert binary to decimal?", a: "Multiply each binary digit by its place value, which is a power of 2, then add the results. For 1101, the values are 8, 4, 0, and 1, so the decimal value is 13." },
  { q: "What is the difference between binary and hexadecimal?", a: "Binary is base 2 and uses 0 and 1. Hexadecimal is base 16 and uses digits 0-9 plus A-F. Hex is a compact way to write binary because each hex digit represents exactly four binary bits." },
  { q: "Why do computers use binary?", a: "Computers use binary because electronic circuits naturally represent two stable states: on and off. Those states map cleanly to 1 and 0, making binary reliable for storage, logic, and computation." },
];

type Operation = "add" | "subtract" | "multiply" | "divide";

function parseBinary(value: string) {
  const clean = value.replace(/\s+/g, "");
  if (!/^[01]+$/.test(clean)) return null;
  return BigInt(`0b${clean}`);
}

function toBinary(value: bigint) {
  return value < 0n ? `-${(-value).toString(2)}` : value.toString(2);
}

export default function BinaryCalculator() {
  const [a, setA] = useState("1010");
  const [b, setB] = useState("11");
  const [operation, setOperation] = useState<Operation>("add");
  const [convertValue, setConvertValue] = useState("1010");
  const [convertBase, setConvertBase] = useState("2");

  const calculation = useMemo(() => {
    const left = parseBinary(a);
    const right = parseBinary(b);
    if (left === null || right === null) return { result: "Invalid binary input", step: "Use only 0 and 1.", decimal: "" };
    if (operation === "divide" && right === 0n) return { result: "Cannot divide by zero", step: "Binary division requires a nonzero divisor.", decimal: "" };
    const value = operation === "add" ? left + right : operation === "subtract" ? left - right : operation === "multiply" ? left * right : left / right;
    const symbol = operation === "add" ? "+" : operation === "subtract" ? "-" : operation === "multiply" ? "x" : "/";
    const remainder = operation === "divide" ? left % right : 0n;
    return {
      result: toBinary(value),
      decimal: value.toString(10),
      step: `${a} (${left.toString(10)}) ${symbol} ${b} (${right.toString(10)}) = ${toBinary(value)}${operation === "divide" && remainder !== 0n ? ` remainder ${toBinary(remainder)}` : ""}`,
    };
  }, [a, b, operation]);

  const conversion = useMemo(() => {
    try {
      const base = Number(convertBase);
      const value = BigInt(parseInt(convertValue, base));
      if (!Number.isFinite(Number(value))) throw new Error("invalid");
      return {
        binary: value.toString(2),
        decimal: value.toString(10),
        hex: value.toString(16).toUpperCase(),
        octal: value.toString(8),
      };
    } catch {
      return { binary: "Invalid", decimal: "Invalid", hex: "Invalid", octal: "Invalid" };
    }
  }, [convertValue, convertBase]);

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all font-mono";

  return (
    <>
      <SEOHead
        title="Free Binary Calculator Online - Add Subtract Multiply Divide Binary Numbers Instantly | CalcHive"
        description="Free online binary calculator. Perform addition, subtraction, multiplication and division on binary numbers and convert between binary, decimal, hex and octal instantly. 100% free, no signup required."
        canonical="/binary-calculator"
        keywords="free binary calculator, binary calculator online free, binary to decimal converter free, binary addition calculator free, binary math calculator free online"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Binary Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free binary calculator to add, subtract, multiply, divide, and convert binary numbers instantly.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div>
              <label htmlFor="binary-a" className="text-sm font-semibold text-foreground block mb-2">Binary A</label>
              <input id="binary-a" value={a} onChange={(event) => setA(event.target.value)} className={inputClass} />
            </div>
            <div>
              <label htmlFor="operation" className="text-sm font-semibold text-foreground block mb-2">Operation</label>
              <select id="operation" value={operation} onChange={(event) => setOperation(event.target.value as Operation)} className={inputClass}>
                <option value="add">Add</option>
                <option value="subtract">Subtract</option>
                <option value="multiply">Multiply</option>
                <option value="divide">Divide</option>
              </select>
            </div>
            <div>
              <label htmlFor="binary-b" className="text-sm font-semibold text-foreground block mb-2">Binary B</label>
              <input id="binary-b" value={b} onChange={(event) => setB(event.target.value)} className={inputClass} />
            </div>
          </div>
          <motion.div key={`${a}-${b}-${operation}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Binary Result</p>
              <p className="text-5xl font-black text-white tracking-tight break-all" data-testid="result-binary">{calculation.result}</p>
              {calculation.decimal && <p className="text-white/70 text-sm mt-1">Decimal: {calculation.decimal}</p>}
            </div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4">
              <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p>
              <p className="text-sm text-foreground font-mono" data-testid="result-steps">{calculation.step}</p>
            </div>
          </motion.div>
        </section>

        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Base Converter</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
            <div>
              <label htmlFor="convert-value" className="text-sm font-semibold text-foreground block mb-2">Value</label>
              <input id="convert-value" value={convertValue} onChange={(event) => setConvertValue(event.target.value)} className={inputClass} />
            </div>
            <div>
              <label htmlFor="convert-base" className="text-sm font-semibold text-foreground block mb-2">Input base</label>
              <select id="convert-base" value={convertBase} onChange={(event) => setConvertBase(event.target.value)} className={inputClass}>
                <option value="2">Binary</option>
                <option value="10">Decimal</option>
                <option value="16">Hexadecimal</option>
                <option value="8">Octal</option>
              </select>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-3">
            {[
              ["Binary", conversion.binary],
              ["Decimal", conversion.decimal],
              ["Hex", conversion.hex],
              ["Octal", conversion.octal],
            ].map(([label, value]) => (
              <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center">
                <p className="text-xs text-muted-foreground font-medium">{label}</p>
                <p className="text-lg font-extrabold text-foreground break-all">{value}</p>
              </div>
            ))}
          </div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Add Subtract Multiply and Divide Binary Numbers for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Enter two binary numbers, choose an operation, and the calculator converts them to decimal, performs the math, and returns the binary result.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Convert Between Binary Decimal Hex and Octal</h2>
          <p className="text-muted-foreground leading-relaxed">Use the base converter to translate the same value across common number systems used in computing and programming.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Binary Math Tool for Students and Programmers</h2>
          <p className="text-muted-foreground leading-relaxed">This binary math calculator free online tool is useful for computer science classes, programming, networking, and digital logic practice.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/binary-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


